INSERT INTO documents (section_slug, page_slug, title, content, updated_by)
VALUES (
  'affiliate',
  'multi-level-structure',
  'Multi-Level Commission Structure',
  $JSON${"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Multi-Level Commission Structure"}]},{"type":"paragraph","content":[{"type":"text","text":"Philippines · PAGCOR Licensed · Up to 5 Levels"}]},{"type":"paragraph","content":[{"type":"text","text":"Flexible commission architecture supporting up to 5 referral levels — from direct media partners to deep sub-affiliate networks. Covers RevShare, CPA, and Hybrid structures with configurable rates per level, negative carryover policy, and full Philippines regulatory context."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Max Levels: 5"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Commission Types: 3"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Max L1 RevShare: 40%"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Min CPA Payout: \u20b12,000"}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Commission Structures"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Revenue Share (RevShare · Recurring)"}]},{"type":"paragraph","content":[{"type":"text","text":"Affiliate earns a percentage of the net gaming revenue (NGR) generated by players they refer — for the lifetime of the player's activity on the platform. The most common long-term affiliate model."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"L1 NGR = Deposits \u2212 Withdrawals \u2212 Bonuses \u2212 Platform Costs"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"L1 Commission = L1 NGR \u00d7 L1 RevShare Rate"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"L2 Override = L1 Commission \u00d7 L2 Sub-Aff Rate"}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Cost Per Acquisition (CPA · One-time)"}]},{"type":"paragraph","content":[{"type":"text","text":"Affiliate earns a fixed flat fee for each new player that registers, completes KYC, and makes a qualifying first deposit above the minimum threshold. Payment is made once per qualifying player."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Qualifying Trigger = KYC Complete + FTD \u2265 \u20b1500"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"CPA Payment = Fixed rate per qualified player"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"L2 CPA Override = Fixed sub-override per qualified player"}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Hybrid (RevShare + CPA · Combined)"}]},{"type":"paragraph","content":[{"type":"text","text":"A negotiated combination of CPA (paid on qualifying first deposit) plus a reduced RevShare rate on ongoing NGR. Preferred by high-volume partners who want immediate income and long-term upside."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Hybrid CPA = Reduced fixed rate per FTD"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Hybrid RevShare = Reduced % NGR (typically 50\u201370% of standard rate)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Must be individually negotiated and documented"}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"5-Level Partner Architecture"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"L1 — Direct Affiliate Partner"}]},{"type":"paragraph","content":[{"type":"text","text":"The primary affiliate who has a signed agreement directly with the operator. Has direct access to the affiliate portal, tracking links, real-time reporting, and their dedicated Affiliate Manager. Earns on all players they directly refer plus an override on any sub-affiliates they recruit below them."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"RevShare: 25\u201340% of NGR"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"CPA: \u20b12,000\u2013\u20b15,000 per FTD"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"L2 Override: 5\u201310% of L2 earnings"}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"L2 — Sub-Affiliate (Recruited by L1)"}]},{"type":"paragraph","content":[{"type":"text","text":"An affiliate recruited into the network by an L1 partner. L2 earns on players they directly refer. L1 earns an override on L2's commissions. L2 may also recruit L3 sub-affiliates and earn a further override. L2 partners typically have portal access at a read-level determined by the L1 partner's agreement."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"RevShare: 20\u201330% of NGR"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"CPA: \u20b11,500\u2013\u20b13,000 per FTD"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"L3 Override: 3\u20136% of L3 earnings"}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"L3 — Third-Level Sub-Affiliate"}]},{"type":"paragraph","content":[{"type":"text","text":"Recruited by an L2 partner. Earns on direct player referrals. Both L1 and L2 earn overrides on L3's commissions in a cascading structure. L3 partners typically operate on a simplified portal view. May recruit L4 if enabled in the programme configuration."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"RevShare: 15\u201325% of NGR"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"CPA: \u20b11,000\u2013\u20b12,000 per FTD"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"L4 Override: 2\u20134% of L4 earnings"}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"L4 — Fourth-Level Partner (Deep Network)"}]},{"type":"paragraph","content":[{"type":"text","text":"L4 recruitment requires explicit Affiliate Manager approval before being enabled. The cascading override structure becomes thinner at this level to maintain operator margin. L4 partners earn reduced RevShare rates and smaller per-FTD CPAs. Overrides from L1, L2, and L3 cascade down. L4 may recruit L5 only with Head of Affiliates sign-off."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"RevShare: 10\u201318% of NGR"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"CPA: \u20b1500\u2013\u20b11,200 per FTD"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"L5 Override: 1\u20132% of L5 earnings"}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"L5 — Fifth-Level Partner (Maximum Depth)"}]},{"type":"paragraph","content":[{"type":"text","text":"The deepest level of the network. L5 earns only on direct player referrals — cannot recruit further sub-affiliates. The programme does not support a Level 6. L5 rates are the most conservative to ensure the total override chain across all 5 levels remains within sustainable operator margin. All 4 upstream levels earn cascading overrides on L5's commissions."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"RevShare: 8\u201312% of NGR"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"CPA: \u20b1300\u2013\u20b1700 per FTD"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Sub-Recruit: Not Permitted (max depth)"}]}]}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"Margin Health — Total Override Cap Principle: The sum of all RevShare rates and override percentages across the full 5-level chain for any single player's NGR must not exceed 65% of that NGR. The Affiliate Manager is responsible for verifying this ceiling is not breached when approving new sub-affiliate agreements or rate negotiations. If a proposed structure would push total payouts above this threshold, rates at the lower levels must be reduced before the agreement is signed."}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Example Cascade Calculation"}]},{"type":"paragraph","content":[{"type":"text","text":"Worked Example — \u20b1100,000 NGR from a single L5-referred player. Assumes a full 5-level chain is active. Each upstream level earns an override on the level directly below them. Total payouts cascade upward simultaneously — they are not deducted sequentially from the player's NGR."}]},{"type":"table","content":[{"type":"tableRow","content":[{"type":"tableHeader","content":[{"type":"paragraph","content":[{"type":"text","text":"Level"}]}]},{"type":"tableHeader","content":[{"type":"paragraph","content":[{"type":"text","text":"Partner Role"}]}]},{"type":"tableHeader","content":[{"type":"paragraph","content":[{"type":"text","text":"Basis"}]}]},{"type":"tableHeader","content":[{"type":"paragraph","content":[{"type":"text","text":"Rate"}]}]},{"type":"tableHeader","content":[{"type":"paragraph","content":[{"type":"text","text":"Calculation"}]}]},{"type":"tableHeader","content":[{"type":"paragraph","content":[{"type":"text","text":"Earnings"}]}]}]},{"type":"tableRow","content":[{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"L5"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"Referring partner (direct referral)"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"Player NGR"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"10% RevShare"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"\u20b1100,000 \u00d7 10%"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"\u20b110,000"}]}]}]},{"type":"tableRow","content":[{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"L4"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"L5's recruiter"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"L5 Earnings"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"2% override on L5"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"\u20b110,000 \u00d7 2%"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"\u20b1200"}]}]}]},{"type":"tableRow","content":[{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"L3"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"L4's recruiter"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"L4 + L5 Earnings"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"3% override on downstream"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"(\u20b110,000 + \u20b1200) \u00d7 3%"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"\u20b1306"}]}]}]},{"type":"tableRow","content":[{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"L2"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"L3's recruiter"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"L3 + L4 + L5 Earnings"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"4% override on downstream"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"(\u20b110,000 + \u20b1200 + \u20b1306) \u00d7 4%"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"\u20b1420"}]}]}]},{"type":"tableRow","content":[{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"L1"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"L2's recruiter"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"L2 + L3 + L4 + L5 Earnings"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"5% override on downstream"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"(\u20b110,000 + \u20b1200 + \u20b1306 + \u20b1420) \u00d7 5%"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"\u20b1546"}]}]}]},{"type":"tableRow","content":[{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"Total payout on \u20b1100,000 NGR (all levels combined)"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":""}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":""}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":""}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":""}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"\u20b111,472 = 11.47% of NGR"}]}]}]}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"Note on override calculation method: Two methods exist — flat NGR override (all levels calculate their override as a % of the player's original NGR) or cascading earnings override (each level earns a % of the level directly below). The example above uses cascading earnings. The flat NGR method results in higher upstream payouts. The chosen method must be explicitly documented in every affiliate agreement to avoid disputes. The Affiliate Manager selects the method at programme setup."}]}]}]}$JSON$::jsonb,
  'system'
)
